// 히든값체크
//-------------------------------------------------------------------------
scwin.f_HiddenCheck = async function (compObj, hidValKey, msg) {

    //이 함수도 결국에는 필요 없네요...
    let val = compObj.getValue().trim();
    if (val == "") return true;
    if (val != hidValKey) {
        await $c.gus.cfAlertMsg("MSG_CM_ERR_038", [msg]);
        compObj.focus();
        return false;
    } else {
        return true;
    }
}

//-------------------------------------------------------------------------
// 팝업체크 - fi_201_01_09b.xml 참고하자...
